 1 | // Package frontmatter 负责解析简单的 YAML 风格 frontmatter。
 2 | // 该能力会被 skills、subagent、memory 等模块复用，避免重复实现元数据读取逻辑。
 3 | package frontmatter
 4 | 
 5 | import "strings"
 6 | 
 7 | // Result 表示 frontmatter 解析结果。
 8 | type Result struct {
 9 | 	// Meta 保存 frontmatter 中的键值对。
10 | 	Meta map[string]string
11 | 	// Body 保存 frontmatter 之后的正文内容。
12 | 	Body string
13 | }
14 | 
15 | // Parse 解析文档中的 frontmatter 与正文。
16 | func Parse(input string) Result {
17 | 	result := Result{
18 | 		Meta: map[string]string{},
19 | 		Body: strings.TrimSpace(input),
20 | 	}
21 | 
22 | 	lines := strings.Split(input, "\n")
23 | 	if len(lines) < 3 || strings.TrimSpace(lines[0]) != "---" {
24 | 		return result
25 | 	}
26 | 
27 | 	end := -1
28 | 	for i := 1; i < len(lines); i++ {
29 | 		if strings.TrimSpace(lines[i]) == "---" {
30 | 			end = i
31 | 			break
32 | 		}
33 | 	}
34 | 	if end == -1 {
35 | 		return result
36 | 	}
37 | 
38 | 	for _, line := range lines[1:end] {
39 | 		parts := strings.SplitN(line, ":", 2)
40 | 		if len(parts) != 2 {
41 | 			continue
42 | 		}
43 | 		key := strings.TrimSpace(parts[0])
44 | 		value := strings.TrimSpace(parts[1])
45 | 		value = strings.Trim(value, `"'`)
46 | 		if key != "" {
47 | 			result.Meta[key] = value
48 | 		}
49 | 	}
50 | 
51 | 	result.Body = strings.TrimSpace(strings.Join(lines[end+1:], "\n"))
52 | 	return result
53 | }
