  1 | // Package skills 负责发现、解析和组织本地技能定义。
  2 | // 本文件对齐 `.claude/skills/<name>/SKILL.md` 约定，支持用户级与项目级覆盖，
  3 | // 并补齐源仓库里的 `when-to-use` 元数据与分组展示能力。
  4 | package skills
  5 | 
  6 | import (
  7 | 	"os"
  8 | 	"path/filepath"
  9 | 	"sort"
 10 | 	"strings"
 11 | 
 12 | 	"mini-claude-code/internal/frontmatter"
 13 | )
 14 | 
 15 | // ContextMode 表示技能的执行上下文模式。
 16 | type ContextMode string
 17 | 
 18 | const (
 19 | 	// ContextInline 表示技能内容直接注入主会话。
 20 | 	ContextInline ContextMode = "inline"
 21 | 	// ContextFork 表示技能内容应交给独立子智能体处理。
 22 | 	ContextFork ContextMode = "fork"
 23 | )
 24 | 
 25 | // Skill 表示一个已发现的技能定义。
 26 | type Skill struct {
 27 | 	// Name 表示技能名称。
 28 | 	Name string
 29 | 	// Description 表示技能说明。
 30 | 	Description string
 31 | 	// WhenToUse 表示技能何时应该被使用。
 32 | 	// 这个字段对齐源仓库的 `when-to-use` 元数据，便于在 system prompt 和 `/skills` 展示更细的触发语义。
 33 | 	WhenToUse string
 34 | 	// Path 表示技能文件完整路径。
 35 | 	Path string
 36 | 	// Source 表示技能来源，例如 `project` 或 `user`。
 37 | 	Source string
 38 | 	// UserInvocable 表示用户是否可以直接通过 `/技能名` 调用。
 39 | 	UserInvocable bool
 40 | 	// Context 表示技能应以内联还是 `fork` 模式生效。
 41 | 	Context ContextMode
 42 | 	// AllowedTools 表示技能显式允许的工具列表。
 43 | 	AllowedTools []string
 44 | 	// PromptTemplate 表示技能正文模板。
 45 | 	PromptTemplate string
 46 | }
 47 | 
 48 | // Store 表示技能存储器。
 49 | type Store struct {
 50 | 	// root 表示项目工作目录。
 51 | 	root string
 52 | }
 53 | 
 54 | // NewStore 创建技能存储器。
 55 | func NewStore(root string) *Store {
 56 | 	return &Store{root: root}
 57 | }
 58 | 
 59 | // Discover 扫描用户级和项目级技能目录，并按项目级覆盖用户级同名技能。
 60 | func (s *Store) Discover() ([]Skill, error) {
 61 | 	resultMap := map[string]Skill{}
 62 | 
 63 | 	for _, source := range []struct {
 64 | 		baseDir string
 65 | 		label   string
 66 | 	}{
 67 | 		{baseDir: filepath.Join(userHomeDir(), ".claude", "skills"), label: "user"},
 68 | 		{baseDir: filepath.Join(s.root, ".claude", "skills"), label: "project"},
 69 | 	} {
 70 | 		loaded, err := s.loadFromDir(source.baseDir, source.label)
 71 | 		if err != nil {
 72 | 			return nil, err
 73 | 		}
 74 | 		for _, skill := range loaded {
 75 | 			resultMap[skill.Name] = skill
 76 | 		}
 77 | 	}
 78 | 
 79 | 	names := make([]string, 0, len(resultMap))
 80 | 	for name := range resultMap {
 81 | 		names = append(names, name)
 82 | 	}
 83 | 	sort.Strings(names)
 84 | 
 85 | 	result := make([]Skill, 0, len(names))
 86 | 	for _, name := range names {
 87 | 		result = append(result, resultMap[name])
 88 | 	}
 89 | 	return result, nil
 90 | }
 91 | 
 92 | // GetByName 根据名称返回单个技能。
 93 | func (s *Store) GetByName(name string) (*Skill, error) {
 94 | 	skills, err := s.Discover()
 95 | 	if err != nil {
 96 | 		return nil, err
 97 | 	}
 98 | 	for _, skill := range skills {
 99 | 		if skill.Name == name {
100 | 			copySkill := skill
101 | 			return &copySkill, nil
102 | 		}
103 | 	}
104 | 	return nil, nil
105 | }
106 | 
107 | // ResolvePrompt 根据传入参数展开技能模板占位符。
108 | func (s *Store) ResolvePrompt(skill Skill, args string) string {
109 | 	prompt := skill.PromptTemplate
110 | 	prompt = strings.ReplaceAll(prompt, "$ARGUMENTS", args)
111 | 	prompt = strings.ReplaceAll(prompt, "${ARGUMENTS}", args)
112 | 	prompt = strings.ReplaceAll(prompt, "${CLAUDE_SKILL_DIR}", filepath.Dir(skill.Path))
113 | 	return prompt
114 | }
115 | 
116 | // BuildPromptSection 构造 system prompt 中的技能描述段落。
117 | // 这里对齐源仓库的展示方式：把“用户可直接调用”和“仅自动调用”的技能分组展示，并补上 when-to-use 提示。
118 | func (s *Store) BuildPromptSection() string {
119 | 	skills, err := s.Discover()
120 | 	if err != nil || len(skills) == 0 {
121 | 		return ""
122 | 	}
123 | 
124 | 	lines := []string{"# Available Skills", ""}
125 | 	userInvocable := make([]Skill, 0, len(skills))
126 | 	autoOnly := make([]Skill, 0, len(skills))
127 | 	for _, skill := range skills {
128 | 		if skill.UserInvocable {
129 | 			userInvocable = append(userInvocable, skill)
130 | 			continue
131 | 		}
132 | 		autoOnly = append(autoOnly, skill)
133 | 	}
134 | 
135 | 	if len(userInvocable) > 0 {
136 | 		lines = append(lines, "User-invocable skills (user types /<name> to invoke):")
137 | 		for _, skill := range userInvocable {
138 | 			description := strings.TrimSpace(skill.Description)
139 | 			if description == "" {
140 | 				description = "No description"
141 | 			}
142 | 			lines = append(lines, "- /"+skill.Name+": "+description)
143 | 			if strings.TrimSpace(skill.WhenToUse) != "" {
144 | 				lines = append(lines, "  When to use: "+strings.TrimSpace(skill.WhenToUse))
145 | 			}
146 | 		}
147 | 		lines = append(lines, "")
148 | 	}
149 | 
150 | 	if len(autoOnly) > 0 {
151 | 		lines = append(lines, "Auto-invocable skills (use the skill tool when appropriate):")
152 | 		for _, skill := range autoOnly {
153 | 			description := strings.TrimSpace(skill.Description)
154 | 			if description == "" {
155 | 				description = "No description"
156 | 			}
157 | 			lines = append(lines, "- "+skill.Name+": "+description)
158 | 			if strings.TrimSpace(skill.WhenToUse) != "" {
159 | 				lines = append(lines, "  When to use: "+strings.TrimSpace(skill.WhenToUse))
160 | 			}
161 | 		}
162 | 		lines = append(lines, "")
163 | 	}
164 | 
165 | 	lines = append(lines, "To invoke a skill programmatically, use the `skill` tool with the skill name and optional arguments.")
166 | 	return strings.Join(lines, "\n")
167 | }
168 | 
169 | // loadFromDir 从给定目录加载技能定义。
170 | func (s *Store) loadFromDir(root string, source string) ([]Skill, error) {
171 | 	if root == "" {
172 | 		return []Skill{}, nil
173 | 	}
174 | 	if _, err := os.Stat(root); err != nil {
175 | 		return []Skill{}, nil
176 | 	}
177 | 
178 | 	entries, err := os.ReadDir(root)
179 | 	if err != nil {
180 | 		return nil, err
181 | 	}
182 | 
183 | 	result := make([]Skill, 0, len(entries))
184 | 	for _, item := range entries {
185 | 		if !item.IsDir() {
186 | 			continue
187 | 		}
188 | 
189 | 		target := filepath.Join(root, item.Name(), "SKILL.md")
190 | 		data, err := os.ReadFile(target)
191 | 		if err != nil {
192 | 			continue
193 | 		}
194 | 
195 | 		parsed := frontmatter.Parse(string(data))
196 | 		context := ContextInline
197 | 		if parsed.Meta["context"] == "fork" {
198 | 			context = ContextFork
199 | 		}
200 | 
201 | 		result = append(result, Skill{
202 | 			Name:           firstNonEmpty(parsed.Meta["name"], item.Name()),
203 | 			Description:    parsed.Meta["description"],
204 | 			WhenToUse:      firstNonEmpty(parsed.Meta["when_to_use"], parsed.Meta["when-to-use"]),
205 | 			Path:           target,
206 | 			Source:         source,
207 | 			UserInvocable:  parsed.Meta["user-invocable"] != "false",
208 | 			Context:        context,
209 | 			AllowedTools:   splitCSV(parsed.Meta["allowed-tools"]),
210 | 			PromptTemplate: parsed.Body,
211 | 		})
212 | 	}
213 | 	return result, nil
214 | }
215 | 
216 | // userHomeDir 返回当前用户主目录，失败时返回空字符串。
217 | func userHomeDir() string {
218 | 	home, err := os.UserHomeDir()
219 | 	if err != nil {
220 | 		return ""
221 | 	}
222 | 	return home
223 | }
224 | 
225 | // firstNonEmpty 返回第一个非空字符串。
226 | func firstNonEmpty(values ...string) string {
227 | 	for _, value := range values {
228 | 		if strings.TrimSpace(value) != "" {
229 | 			return value
230 | 		}
231 | 	}
232 | 	return ""
233 | }
234 | 
235 | // splitCSV 把逗号分隔内容拆成字符串数组。
236 | func splitCSV(raw string) []string {
237 | 	if strings.TrimSpace(raw) == "" {
238 | 		return nil
239 | 	}
240 | 	parts := strings.Split(raw, ",")
241 | 	result := make([]string, 0, len(parts))
242 | 	for _, part := range parts {
243 | 		trimmed := strings.TrimSpace(part)
244 | 		if trimmed != "" {
245 | 			result = append(result, trimmed)
246 | 		}
247 | 	}
248 | 	return result
249 | }
